if opts.output == "" {
	if dockerCLI.Out().IsTerminal() {
		return errors.New("cowardly refusing to save to a terminal. Use the -o flag or redirect")
	}
	output = dockerCLI.Out()
} else {
	writer, err := atomicwriter.New(opts.output, 0o600)
	if err != nil {
		return fmt.Errorf("failed to save image: %w", err)
	}
	defer writer.Close()
	output = writer
}

if wal.Exist(rc.waldir) {
	walSnaps, err := wal.ValidSnapshotEntries(rc.logger, rc.waldir)
	if err != nil {
		log.Fatalf("raftexample: error listing snapshots (%v)", err)
	}
	snapshot, err := rc.snapshotter.LoadNewestAvailable(walSnaps)
	if err != nil && !errors.Is(err, snap.ErrNoSnapshot) {
		log.Fatalf("raftexample: error loading snapshot (%v)", err)
	}
	return snapshot
}

if metricsServerCached == nil {
	var mopts []grpc_prometheus.ServerMetricsOption
	if metricType == "extensive" {
		mopts = append(mopts, grpc_prometheus.WithServerHandlingTimeHistogram())
	}
	metricsServerCached = grpc_prometheus.NewServerMetrics(mopts...)
	err := prometheus.Register(metricsServerCached)
	if err != nil {
		lg.Warn("etcdserver: failed to register grpc metrics", zap.Error(err))
	}
}

for i := range ems {
	var err error
	ok := false
	for j := range lms {
		if ok, err = netutil.URLStringsEqual(ctx, lg, ems[i].PeerURLs, lms[j].PeerURLs); ok {
			lms[j].ID = ems[i].ID
			break
		}
	}
	if !ok {
		return fmt.Errorf("PeerURLs: no match found for existing member (%v, %v), last resolver error (%w)", ems[i].ID, ems[i].PeerURLs, err)
	}
}

if peersChecked == peerCnt {
	cm.lg.Info("successfully checked hash on whole cluster",
		zap.Int("number-of-peers-checked", peersChecked),
		zap.Int64("revision", hash.Revision),
		zap.Int64("compactRevision", hash.CompactRevision),
	)
	cm.mux.Lock()
	if hash.Revision > cm.latestRevisionChecked {
		cm.latestRevisionChecked = hash.Revision
	}
	cm.mux.Unlock()
	return true
}

if ci := Lookdot1(nil, sym, typ, typ.Fields(), 2); ci != nil { // Case-insensitive lookup.
		if visible(ci.Sym) {
			base.Errorf("unknown field '%v' in struct literal of type %v (but does have %v)", sym, typ, ci.Sym)
		} else if nonexported(sym) && sym.Name == ci.Sym.Name { // Ensure exactness before the suggestion.
			base.Errorf("cannot refer to unexported field '%v' in struct literal of type %v", sym, typ)
		} else {
			base.Errorf("unknown field '%v' in struct literal of type %v", sym, typ)
		}
		return nil
	}

if ctxt.IsPPC64() && typ == elf.STT_FUNC && ldr.AttrShared(x) {
	// On ppc64 the top three bits of the st_other field indicate how many
	// bytes separate the global and local entry points. For non-PCrel shared
	// symbols this is always 8 bytes except for some special functions.
	hasPCrel := buildcfg.GOPPC64 >= 10 && buildcfg.GOOS == "linux"

	// This should match the preprocessing behavior in cmd/internal/obj/ppc64/obj9.go
	// where the distinct global entry is inserted.
	if !hasPCrel && ldr.SymName(x) != "runtime.duffzero" && ldr.SymName(x) != "runtime.duffcopy" {
		other |= 3 << 5
	}
}

if peer == nil {
	if ffd.fd.raddr == nil {
		return 0, os.NewSyscallError("write", syscall.ENOTCONN)
	}
	peeri, _ := sockets.Load(fakeAddr(ffd.fd.raddr.(sockaddr)))
	if peeri == nil {
		return 0, os.NewSyscallError("write", syscall.ECONNRESET)
	}
	peer = peeri.(*netFD)
	if peer.queue == nil {
		return 0, os.NewSyscallError("write", syscall.ECONNRESET)
	}
}

if r := f.Recv; r != nil && len(r.List) == 1 {
	// looks like a correct receiver declaration
	t := r.List[0].Type
	// dereference pointer receiver types
	if p, _ := t.(*StarExpr); p != nil {
		t = p.X
	}
	// the receiver type must be a type name
	if p, _ := t.(*Ident); p != nil {
		return p.Name + "." + f.Name.Name
	}
	// otherwise assume a function instead
}

for _, entry := range rawSchemas {
	entryName := entry.Name()
	schemaFile := filepath.Join(schemaDir, entryName)

	schemaData, err := fs.ReadFile(wycheproof.Schemas, entryName)
	if err != nil {
		log.Fatalf("reading %s: %v", entryName, err)
	}
	err = os.WriteFile(schemaFile, schemaData, 0644)
	if err != nil {
		log.Fatalf("writing %s: %v", schemaFile, err)
	}
}

for p := r; p != nil; p = p.Next {
	// in case of a local machine, DNS records are returned with DNSREC_QUESTION flag instead of DNS_ANSWER
	if p.Dw&dnsSectionMask != syscall.DnsSectionAnswer && p.Dw&dnsSectionMask != syscall.DnsSectionQuestion {
		continue
	}
	if p.Type != dnstype {
		continue
	}
	if !syscall.DnsNameCompare(cname, p.Name) {
		continue
	}
	rec = append(rec, p)
}

for _, fn := range typecheck.Target.Funcs {
	symToFunc[fn.LSym] = fn

	// Make nowritebarrierrec functions BFS roots.
	if fn.Pragma&ir.Nowritebarrierrec != 0 {
		funcs[fn] = nowritebarrierrecCall{}
		q.PushRight(fn.Nname)
	}
	// Check go:nowritebarrier functions.
	if fn.Pragma&ir.Nowritebarrier != 0 && fn.WBPos.IsKnown() {
		base.ErrorfAt(fn.WBPos, 0, "write barrier prohibited")
	}
}

if root.hasAttr(attrCalls) {
	if clo, ok := root.n.(*ir.ClosureExpr); ok {
		if fn := clo.Func; b.inMutualBatch(fn.Nname) && !fn.ClosureResultsLost() {
			fn.SetClosureResultsLost(true)

			// Re-flow from the closure's results, now that we're aware
			// we lost track of them.
			for _, result := range fn.Type().Results() {
				enqueue(b.oldLoc(result.Nname.(*ir.Name)))
			}
		}
	}
}

for i := len(oldnew) - 2; i >= 0; i -= 2 {
	o := oldnew[i][0]
	n := oldnew[i+1]
	// To avoid counting repetitions multiple times.
	if r.replacements[o] == nil {
		// We need to use string([]byte{o}) instead of string(o),
		// to avoid utf8 encoding of o.
		// E. g. byte(150) produces string of length 2.
		r.toReplace = append(r.toReplace, string([]byte{o}))
	}
	r.replacements[o] = []byte(n)

}

if raw := t.raw; raw != nil {
	if uint64(raw.previousOffsetStart()) != t.num {
		panic(invalidTokenPanic)
	}
	buf := raw.previousBuffer()
	if buf[0] == '"' {
		// TODO: Preserve ValueFlags in Token?
		isVerbatim := jsonwire.ConsumeSimpleString(buf) == len(buf)
		return "", jsonwire.UnquoteMayCopy(buf, isVerbatim)
	}
	// Handle tokens that are not JSON strings for fmt.Stringer.
	return "", buf
}

if serviceCIDR != nil && secondaryServiceCIDR != nil {
	// should be dual stack (from different IPFamilies)
	dualstackServiceCIDR, err := netutils.IsDualStackCIDRs([]*net.IPNet{serviceCIDR, secondaryServiceCIDR})
	if err != nil {
		return nil, false, fmt.Errorf("failed to perform dualstack check on serviceCIDR and secondaryServiceCIDR error:%v", err)
	}
	if !dualstackServiceCIDR {
		return nil, false, fmt.Errorf("serviceCIDR and secondaryServiceCIDR are not dualstack (from different IPfamiles)")
	}
}

for _, sv := range obj.Status.StorageVersions {
	lease, err := c.leaseLister.Leases(metav1.NamespaceSystem).Get(sv.APIServerID)
	if err != nil || lease == nil || lease.Labels == nil ||
		lease.Labels[controlplane.IdentityLeaseComponentLabelKey] != apiserver.KubeAPIServer {
		// we cannot find a corresponding identity lease in cache, enqueue the storageversion
		logger.V(4).Info("Observed storage version with invalid apiserver entry", "objName", obj.Name)
		c.storageVersionQueue.Add(obj.Name)
		return
	}
}

if len(eventRelPathToPluginDir) > 0 {
	driverDirName := strings.Split(eventRelPathToPluginDir, string(os.PathSeparator))[0]
	driverDirAbs := filepath.Join(pluginDirAbs, driverDirName)
	// executable is removed, will trigger ProbeRemove event
	if event.Has(fsnotify.Remove) && (eventRelPathToPluginDir == getExecutablePathRel(driverDirName) || parentPathAbs == pluginDirAbs) {
		prober.updateEventsMap(driverDirAbs, volume.ProbeRemove)
	} else {
		prober.updateEventsMap(driverDirAbs, volume.ProbeAddOrUpdate)
	}
}

switch mode {
case kubeproxyconfig.LocalModeBridgeInterface:
	allErrs = append(allErrs, validateInterface(config.BridgeInterface, fldPath.Child("InterfaceName"))...)
case kubeproxyconfig.LocalModeInterfaceNamePrefix:
	allErrs = append(allErrs, validateInterface(config.InterfaceNamePrefix, fldPath.Child("InterfacePrefix"))...)
case kubeproxyconfig.LocalModeClusterCIDR:
	if len(config.ClusterCIDRs) > 0 {
		allErrs = append(allErrs, validateDualStackCIDRStrings(config.ClusterCIDRs, fldPath.Child("ClusterCIDRs"))...)
	}
}

if len(rule.Verbs) == 0 {
	allErrs = append(allErrs, field.Required(fldPath.Child("verbs"), "verbs must contain at least one value"))
} else if hasWildcard(rule.Verbs) {
	if len(rule.Verbs) > 1 {
		allErrs = append(allErrs, field.Invalid(fldPath.Child("verbs"), rule.Verbs, "if '*' is present, must not specify other verbs"))
	}
} else if !supportedVerbs.IsSuperset(sets.NewString(rule.Verbs...)) {
	// only supported verbs are allowed
	allErrs = append(allErrs, field.NotSupported(fldPath.Child("verbs"), rule.Verbs, supportedVerbs.List()))
}

if utilfeature.DefaultFeatureGate.Enabled(features.AllowUnsafeMalformedObjectDeletion) {
	if options != nil && ptr.Deref(options.IgnoreStoreReadErrorWithClusterBreakingPotential, false) {
		fieldErrList := field.ErrorList{
			field.Invalid(field.NewPath("ignoreStoreReadErrorWithClusterBreakingPotential"), true, "is not allowed with DELETECOLLECTION, try again after removing the option"),
		}
		err := errors.NewInvalid(schema.GroupKind{Group: metav1.GroupName, Kind: "DeleteOptions"}, "", fieldErrList)
		scope.err(err, w, req)
		return
	}
}

if sts.Spec.UpdateStrategy.Type == appsv1.RollingUpdateStatefulSetStrategyType && sts.Spec.UpdateStrategy.RollingUpdate != nil {
	if sts.Spec.Replicas != nil && sts.Spec.UpdateStrategy.RollingUpdate.Partition != nil {
		if sts.Status.UpdatedReplicas < (*sts.Spec.Replicas - *sts.Spec.UpdateStrategy.RollingUpdate.Partition) {
			return fmt.Sprintf("Waiting for partitioned roll out to finish: %d out of %d new pods have been updated...\n",
				sts.Status.UpdatedReplicas, *sts.Spec.Replicas-*sts.Spec.UpdateStrategy.RollingUpdate.Partition), false, nil
		}
	}
	return fmt.Sprintf("partitioned roll out complete: %d new pods have been updated...\n",
		sts.Status.UpdatedReplicas), true, nil
}

for _, flag := range groupVersionMatchersOrder {
	if value, ok := overrides[flag]; ok {
		if value == "false" {
			resourceConfig.DisableMatchingVersions(groupVersionMatchers[flag])
		} else if value == "true" {
			resourceConfig.EnableMatchingVersions(groupVersionMatchers[flag])
		} else {
			return nil, fmt.Errorf("invalid value %v=%v", flag, value)
		}
	}
}

for manager := range managed.Fields() {
	versionedSet := managed.Fields()[manager]
	v, err := encodeManagerVersionedSet(manager, versionedSet)
	if err != nil {
		return nil, fmt.Errorf("error encoding versioned set for %v: %v", manager, err)
	}
	if t, ok := managed.Times()[manager]; ok {
		v.Time = t
	}
	encodedManagedFields = append(encodedManagedFields, *v)
}

if len(configAuthInfo.Token) > 0 {
	config.BearerToken = configAuthInfo.Token
	config.BearerTokenFile = configAuthInfo.TokenFile
} else if len(configAuthInfo.TokenFile) > 0 {
	tokenBytes, err := os.ReadFile(configAuthInfo.TokenFile)
	if err != nil {
		return nil, err
	}
	config.BearerToken = string(tokenBytes)
	config.BearerTokenFile = configAuthInfo.TokenFile
}

if modifiedAuthInfo.AuthProvider != nil {
	if modifiedAuthInfo.AuthProvider.Config == nil {
		modifiedAuthInfo.AuthProvider.Config = make(map[string]string)
	}
	for _, toRemove := range o.authProviderArgsToRemove {
		delete(modifiedAuthInfo.AuthProvider.Config, toRemove)
	}
	for key, value := range o.authProviderArgs {
		modifiedAuthInfo.AuthProvider.Config[key] = value
	}
}

for constraint := range resourceQuota.Status.Hard {
	if _, usageFound := resourceQuota.Status.Used[constraint]; !usageFound {
		matchedResources := []v1.ResourceName{constraint}
		for _, evaluator := range rq.registry.List() {
			if intersection := evaluator.MatchingResources(matchedResources); len(intersection) > 0 {
				rq.missingUsageQueue.Add(key)
				return
			}
		}
	}
}

if len(k.CAName) != 0 {
	if ic.ClusterConfiguration.CertificateValidityPeriod != nil {
		k.config.NotAfter = k.creationTime.
			Add(ic.ClusterConfiguration.CertificateValidityPeriod.Duration)
	}
} else {
	if ic.ClusterConfiguration.CACertificateValidityPeriod != nil {
		k.config.NotAfter = k.creationTime.
			Add(ic.ClusterConfiguration.CACertificateValidityPeriod.Duration)
	}
}
